INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2027, 210734, 10, 2270, '记忆是一种很玄的东西――给五叶桔', '五叶桔，读过你的许多文章，包括橘子的舞蹈，也曾被深深的触动过。不过，一直以来都不大能理解你所谓的感情。现在的你，已经释怀了吗？忘却了吗？曾经的他，还在你心里很深很深的地方吗？或者……请原谅我那无力的好奇，只是难以明白，是怎样的力量，让你在当时坚定的说出“我不再爱你”……
<br>  记忆是一种很玄的东西，有时侯，她会象胸口的一颗红胎记，挥之不去，又难以割舍……', '五叶桔，读过你的许多文章，包括橘子的舞蹈，也曾被深深的触动过。不过，一直以来都不大能理解你所谓的感情。现在的你，已经释怀了吗？忘却了吗？曾经的他，还在你心里很深很深的地方吗？或者……请原谅我那无力的好奇，只是难以明白，是怎样的力量，让你在当时坚定的说出“我不再爱你”……

